import java.util.*;

public class TreeTypeChecker {

    static class TreeNode {
        int val; TreeNode left, right;
        TreeNode(int v) { val = v; }
    }

    private int height(TreeNode root) {
        if (root == null) return 0;
        return 1 + Math.max(height(root.left), height(root.right));
    }

    public boolean isPerfect(TreeNode root) {
        int h = height(root);
        // A perfect tree of height h has 2^h - 1 nodes
        // TODO: count nodes and compare with (int)Math.pow(2, h) - 1
        return false;
    }

    public boolean isComplete(TreeNode root) {
        // BFS: once a node with fewer than 2 children is seen, all subsequent must be leaves
        if (root == null) return true;
        Queue<TreeNode> queue = new LinkedList<>();
        queue.add(root);
        boolean foundNonFull = false;
        while (!queue.isEmpty()) {
            TreeNode curr = queue.poll();
            if (curr.left != null) {
                if (foundNonFull) return false;
                queue.add(curr.left);
            } else foundNonFull = true;
            if (curr.right != null) {
                if (foundNonFull) return false;
                queue.add(curr.right);
            } else foundNonFull = true;
        }
        return true;
    }

    private int countNodes(TreeNode root) {
        if (root == null) return 0;
        return 1 + countNodes(root.left) + countNodes(root.right);
    }

    public static void main(String[] args) {
        TreeTypeChecker tc = new TreeTypeChecker();
        // Perfect tree
        TreeNode perfect = new TreeNode(1);
        perfect.left = new TreeNode(2); perfect.right = new TreeNode(3);
        perfect.left.left = new TreeNode(4); perfect.left.right = new TreeNode(5);
        perfect.right.left = new TreeNode(6); perfect.right.right = new TreeNode(7);
        System.out.println("Perfect tree - isPerfect: " + tc.isPerfect(perfect));
        System.out.println("Perfect tree - isComplete: " + tc.isComplete(perfect));
        // Complete but not perfect
        TreeNode complete = new TreeNode(1);
        complete.left = new TreeNode(2); complete.right = new TreeNode(3);
        complete.left.left = new TreeNode(4);
        System.out.println("Complete tree - isPerfect: " + tc.isPerfect(complete));
        System.out.println("Complete tree - isComplete: " + tc.isComplete(complete));
    }
}

