public class TreeMeasures {

    static class TreeNode {
        int val; TreeNode left, right;
        TreeNode(int v) { val = v; }
    }

    public int size(TreeNode root) {
        if (root == null) return 0;
        return 1 + size(root.left) + size(root.right);
    }

    private int[] diameterHelper(TreeNode root) {
        if (root == null) return new int[]{0, 0}; // {height, diameter}
        int[] left = diameterHelper(root.left);
        int[] right = diameterHelper(root.right);
        int height = 1 + Math.max(left[0], right[0]);
        int throughRoot = left[0] + right[0];
        int diameter = Math.max(throughRoot, Math.max(left[1], right[1]));
        return new int[]{height, diameter};
    }

    public int diameter(TreeNode root) {
        return diameterHelper(root)[1];
    }

